require __DIR__ . '/../includes/admin_catalog.php';
require_once __DIR__ . '/../includes/backup_release.php';
sf_sec_require('admin.ops.manage');
if (($_SERVER['REQUEST_METHOD'] ?? 'GET') === 'POST') {
  $action=(string)($_POST['action']??'');
  if($action==='save_release'){ $id=sf_rel_create_or_update($_POST,(int)($_POST['release_id']??0)); sf_admin_flash($id?'success':'error',$id?'Release saved.':'Release was not saved. Run migration 019.'); sf_admin_redirect($id?sf_url('admin/releases.php?release_id='.$id):null); }
  if($action==='update_task'){ sf_rel_update_task((int)($_POST['task_id']??0),(string)($_POST['status']??'pending'),(string)($_POST['detail']??'')); sf_admin_flash('success','Release task updated.'); }
  if($action==='event'){ sf_rel_event((int)($_POST['release_id']??0),(string)($_POST['event_type']??'manual_event'),(string)($_POST['event_status']??'info'),(string)($_POST['title']??'Release event'),(string)($_POST['detail']??'')); sf_admin_flash('success','Release event added.'); }
  sf_admin_redirect(sf_url('admin/releases.php'.(!empty($_POST['release_id'])?'?release_id='.(int)$_POST['release_id']:'')));
}
require __DIR__ . '/../includes/header.php';
$summary=sf_br_summary();
$releases=sf_rel_releases(120);
$backups=sf_br_runs(80);
$selectedId=(int)($_GET['release_id']??($releases[0]['id']??0));
$selected=$selectedId?sf_rel_release($selectedId):null;
$tasks=$selectedId?sf_rel_tasks($selectedId):[];
$events=$selectedId?sf_rel_events($selectedId,100):sf_rel_events(0,80);
$migrations=sf_br_schema_status();
sf_admin_shell_start('Release Manager', 'Deployment release manager v1', 'Track release versions, deployment checklists, migration ranges, backup links, release events, smoke-test status, and rollback notes.', 'releases');
?>
